import requests
from functools import lru_cache


class Geocoder:
    """Geocoding service with configurable provider."""

    def __init__(self, provider_url="https://maps.example.com/api/geocode"):
        self.provider_url = provider_url
        self.geocode = lru_cache(maxsize=1024)(self._geocode)

    def _geocode(self, address):
        """Convert an address string to lat/lng coordinates."""
        response = requests.get(self.provider_url, params={"q": address})
        response.raise_for_status()
        data = response.json()
        return {"lat": data["lat"], "lng": data["lng"]}

    def reverse_geocode(self, lat, lng):
        """Convert coordinates to an address."""
        response = requests.get(
            self.provider_url, params={"lat": lat, "lng": lng, "reverse": True}
        )
        response.raise_for_status()
        return response.json()["address"]

    def geocode_batch(self, addresses):
        """Geocode multiple addresses, leveraging the cache."""
        return [self.geocode(addr) for addr in addresses]

