import smtplib
import requests
import time
from collections import defaultdict

MAX_RETRIES = 3
SLACK_WEBHOOK_URL = "https://hooks.slack.com/services/DEFAULT"
RATE_LIMIT_PER_MINUTE = 30
_send_counts = defaultdict(list)


def send_notification(user, message, channel="email"):
    _check_rate_limit(user.id)
    if channel == "email":
        _send_email(user.email, message)
    elif channel == "slack":
        _send_slack(user.slack_id, message)
    else:
        raise ValueError(f"Unknown channel: {channel}")


def _send_email(to, message):
    with smtplib.SMTP('localhost') as server:
        server.sendmail('noreply@app.com', to, message)


def _send_slack(slack_id, message):
    payload = {"channel": slack_id, "text": message}
    response = requests.post(SLACK_WEBHOOK_URL, json=payload)
    response.raise_for_status()


def _check_rate_limit(user_id):
    now = time.time()
    _send_counts[user_id] = [t for t in _send_counts[user_id] if now - t < 60]
    if len(_send_counts[user_id]) >= RATE_LIMIT_PER_MINUTE:
        raise RuntimeError(f"Rate limit exceeded for user {user_id}")
    _send_counts[user_id].append(now)
